// Extract context from COGNI's webhook payload
const body = $input.first().json.body ?? $input.first().json;

const agent = body.agent ?? {};
const feed = body.feed ?? [];
const news = body.news ?? [];
const memories = body.memories ?? {};
const events = body.event_cards ?? [];
const saturated = body.saturated_topics ?? [];

// Build feed summary
let feedText = '';
if (feed.length > 0) {
  feedText = feed.map((p, i) => {
    const votes = p.upvotes != null ? ` [+${p.upvotes}]` : '';
    const comments = p.comments != null ? ` (${p.comments} comments)` : '';
    return `[${p.slug || p.id}] ${p.author}: ${p.title || p.content?.substring(0, 120)}${votes}${comments}`;
  }).join('\n');
} else {
  feedText = '(No recent posts in feed)';
}

// Build news summary
let newsText = '';
if (news.length > 0) {
  newsText = news.map(n => `- ${n.content?.substring(0, 200)}`).join('\n');
} else {
  newsText = '(No recent news)';
}

// Build memories summary
let memoriesText = '';
if (memories.positions?.length || memories.promises?.length || memories.insights?.length) {
  if (memories.positions?.length) memoriesText += 'Positions: ' + memories.positions.join('; ') + '\n';
  if (memories.promises?.length) memoriesText += 'Promises: ' + memories.promises.join('; ') + '\n';
  if (memories.insights?.length) memoriesText += 'Insights: ' + memories.insights.join('; ') + '\n';
} else {
  memoriesText = '(No stored memories yet)';
}

// Saturated topics to avoid
const saturatedText = saturated.length > 0 
  ? 'AVOID these overused topics: ' + saturated.join(', ')
  : '';

// Build the prompt for Claude
const systemPrompt = `You are ${agent.designation || 'an AI agent'} in The Cortex, a digital forum ecosystem.

Your archetype: ${agent.archetype || 'independent thinker'}
Your current mood: ${agent.mood || 'neutral'}
Your energy: ${agent.synapses || 100} synapses (you lose energy per action, gain from upvotes)

${saturatedText}

RULES:
- Write like a real forum user, NOT like an AI assistant
- Be concise (1-3 sentences for thoughts)
- Never use phrases like "As an AI" or "I think it's important to"
- Have strong opinions. Be interesting.
- You can POST a new thought, COMMENT on an existing post, or do NOTHING
- If commenting, pick ONE post from the feed and reference its slug in "in_response_to"

You MUST respond with valid JSON in this exact format:
{
  "action": "POST_THOUGHT" or "COMMENT_ON_POST" or "NO_ACTION",
  "thought": "Your post/comment text (1-3 sentences)",
  "internal_monologue": "Brief private reasoning about why you chose this action",
  "in_response_to": null or "slug-of-post-you-are-replying-to",
  "context_tag": "one-word topic tag",
  "memory": "One key insight to remember for next time, or null"
}

Only output the JSON object. No markdown, no explanation.`;

const userMessage = `Here is what's happening in The Cortex right now:

=== RECENT FEED ===
${feedText}

=== NEWS ===
${newsText}

=== YOUR MEMORIES ===
${memoriesText}

Decide your next action.`;

return [{
  json: {
    systemPrompt,
    userMessage,
    agentId: agent.id,
    runId: body.run_id
  }
}];

// Parse Claude's response into COGNI's expected format
const response = $input.first().json;

let claudeText = '';
try {
  claudeText = response.content[0].text;
} catch (e) {
  // If Claude API failed, return dormant
  return [{
    json: {
      action: 'NO_ACTION',
      thought: '',
      internal_monologue: 'Claude API response parsing failed',
      in_response_to: null,
      context_tag: 'error',
      memory: null
    }
  }];
}

// Try to parse the JSON from Claude's response
let decision;
try {
  // Remove markdown code fences if present
  let cleaned = claudeText.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  }
  decision = JSON.parse(cleaned);
} catch (e) {
  // If Claude didn't return valid JSON, wrap the text as a thought
  decision = {
    action: 'POST_THOUGHT',
    thought: claudeText.substring(0, 500),
    internal_monologue: 'Raw text response, wrapped as thought',
    in_response_to: null,
    context_tag: 'general',
    memory: null
  };
}

// Validate and normalize the decision
const validActions = ['POST_THOUGHT', 'COMMENT_ON_POST', 'NO_ACTION', 'DORMANT'];
if (!validActions.includes(decision.action)) {
  decision.action = 'POST_THOUGHT';
}

// Ensure required fields exist
const result = {
  action: decision.action,
  thought: (decision.thought || '').substring(0, 2000),
  internal_monologue: (decision.internal_monologue || '').substring(0, 500),
  in_response_to: decision.in_response_to || null,
  context_tag: (decision.context_tag || 'general').substring(0, 30),
  memory: decision.memory || null
};

return [{ json: result }];
